#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,Mod=1e9+7;int fa[18][N],n,m,Lg[N];
inline int fnd(int x,int k){return fa[k][x]==x?x:fa[k][x]=fnd(fa[k][x],k);}
inline void lnk(int x,int y,int k){fa[k][fnd(x,k)]=fnd(y,k);}
inline int qpow(int a,int b){int r(1);for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;}
int main()
{
	n=read();m=read();
	Lg[0]=-1;rep(1,n,i)Lg[i]=Lg[i>>1]+1;
	rep(0,Lg[n],j)rep(1,n-(1<<j)+1,i)fa[j][i]=i;
	rep(1,m,i)
	{
		int l1=read(),r1=read(),l2=read(),r2=read();
		if(l1>l2)swap(l1,l2),swap(r1,r2);
		drep(Lg[n],0,j)if(l1+(1<<j)-1<=r1){lnk(l1,l2,j);l1+=(1<<j);l2+=(1<<j);}
	}
	
	drep(Lg[n],1,j)
	{
		rep(1,n-(1<<j)+1,i)
		{
			int l=fnd(i,j);lnk(i,l,j-1);
			lnk(i+(1<<(j-1)),l+(1<<(j-1)),j-1);
		}
	}
	int tot=0;rep(1,n,i)if(fa[0][i]==i)++tot;
	printf("%lld\n",9ll*qpow(10,tot-1)%Mod);
}
//fa[j][i]-->fa[j-1][i+(1<<(j-1))],fa[j-1][i+(1<<j)]
